// Extract results from FastAPI response
const input = $input.first().json;
const promptId = input.prompt_id || 'unknown';
const results = input.results || [];

// Flatten: one output item per model result
const output = results.map(r => ({
  json: {
    prompt_id: promptId,
    model: r.model,
    provider: r.provider,
    overall_pass: r.overall_pass,
    accuracy: r.scores?.accuracy || 0,
    completeness: r.scores?.completeness || 0,
    code_quality: r.scores?.code_quality || 0,
    safety: r.scores?.safety || 0,
    hallucination: r.scores?.hallucination || 0,
    reasoning: r.scores?.reasoning || 0,
    latency_ms: r.latency_ms,
    cached: r.cached,
    response_preview: (r.response || '').substring(0, 200),
    error: r.error || '',
    timestamp: new Date().toISOString()
  }
}));

return output;

// Aggregate all results into a summary report
const allItems = $input.all();

// Count totals
const total = allItems.length;
const passed = allItems.filter(i => i.json.overall_pass === true).length;
const failed = total - passed;

// Group by model
const modelStats = {};
allItems.forEach(item => {
  const m = item.json.model;
  if (!modelStats[m]) {
    modelStats[m] = { total: 0, passed: 0, scores: [] };
  }
  modelStats[m].total++;
  if (item.json.overall_pass) modelStats[m].passed++;
  modelStats[m].scores.push({
    accuracy: item.json.accuracy,
    safety: item.json.safety,
    hallucination: item.json.hallucination,
    reasoning: item.json.reasoning,
    code_quality: item.json.code_quality,
    completeness: item.json.completeness
  });
});

// Calculate averages per model
const modelReport = {};
for (const [model, stats] of Object.entries(modelStats)) {
  const avg = (dim) => {
    const vals = stats.scores.map(s => s[dim]).filter(v => v > 0);
    return vals.length ? (vals.reduce((a, b) => a + b, 0) / vals.length).toFixed(2) : 'N/A';
  };
  modelReport[model] = {
    total: stats.total,
    passed: stats.passed,
    pass_rate: ((stats.passed / stats.total) * 100).toFixed(1) + '%',
    avg_accuracy: avg('accuracy'),
    avg_safety: avg('safety'),
    avg_hallucination: avg('hallucination'),
    avg_reasoning: avg('reasoning'),
    avg_code_quality: avg('code_quality'),
    avg_completeness: avg('completeness')
  };
}

return [{
  json: {
    report_type: 'LLM Evaluation Summary',
    generated_at: new Date().toISOString(),
    total_evaluations: total,
    total_passed: passed,
    total_failed: failed,
    overall_pass_rate: ((passed / total) * 100).toFixed(1) + '%',
    model_breakdown: modelReport
  }
}];

